SELECT id1, UNNEST(somelist) AS element
FROM tbl2
WHERE id1=10;

SELECT id1, element
FROM (
      SELECT id1, UNNEST(somelist) AS element
      FROM tbl2
    ) tmp
WHERE id1=10;

SELECT id1, generate_subscripts(somelist, 1) AS index, UNNEST(somelist) AS element
      FROM tbl2
)
SELECT id1, index, element
FROM tmp
WHERE id1=10;
